# partner_integration_model.py
# Compute 3-year TCO for a partner integration scenario

PHASE_COSTS = {
    "pre_integration": {"low": 25_000, "high": 100_000},
    "build":           {"low": 75_000, "high": 350_000},
    "stabilisation":   {"low": 20_000, "high": 80_000},
}

ANNUAL_OPS = {"low": 60_000, "high": 400_000}

MULTIPLIERS = {
    "base":             1.0,
    "streaming":        1.3,
    "multi_region":     1.4,
    "legacy_systems":   1.5,
    "regulated":        1.6,
}

def compute_tco(multipliers: list[str], years: int = 3) -> dict:
    m = 1.0
    for key in multipliers:
        m *= MULTIPLIERS[key]

    one_time = {
        band: sum(PHASE_COSTS[p][band] for p in PHASE_COSTS) * m
        for band in ("low", "high")
    }
    recurring = {band: ANNUAL_OPS[band] * m * years for band in ("low", "high")}

    return {
        "one_time":  one_time,
        "recurring": recurring,
        "total_low":  one_time["low"] + recurring["low"],
        "total_high": one_time["high"] + recurring["high"],
        "multiplier": m,
        "years": years,
    }

# Example: streaming + regulated
result = compute_tco(["streaming", "regulated"])
print(f"3-year TCO: ${result['total_low']:,.0f} – ${result['total_high']:,.0f}")
print(f"Multiplier: {result['multiplier']:.2f}×")
# 3-year TCO: $347,100 – $1,547,400
# Multiplier: 2.08×
